<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Fricção do Pagamento Cripto Offline vs. a Solução INSPAY × Sui</text>
  <g font-family="sans-serif">
    <rect x="24" y="55" width="315" height="300" rx="10" fill="#1c1c1f" stroke="#f87171" stroke-width="1.5"/>
    <text x="181" y="86" fill="#f87171" font-size="13" font-weight="700" text-anchor="middle">Pagamento On-Chain Tradicional (BTC, ETH)</text>
    <text x="181" y="126" fill="#e4e4e7" font-size="12" text-anchor="middle">Finalidade: BTC ~10 min, ETH ~12-15 seg</text>
    <text x="181" y="158" fill="#e4e4e7" font-size="14" text-anchor="middle">Gas: pago pelo usuário</text>
    <text x="181" y="190" fill="#e4e4e7" font-size="13" text-anchor="middle">Barreira: exige token nativo</text>
    <text x="181" y="222" fill="#e4e4e7" font-size="12" text-anchor="middle">Caso: Chivo El Salvador 2021 (via Lightning)</text>
